a.code:
const user = Object.freeze({
  name: 'Sarah',
  tags: ['dev', 'lead']
});

// Shallow! Nested still mutable:
user.tags.push('admin'); // works!

b.code:
const user = #{
  name: 'Sarah',
  tags: #['dev', 'lead']
};

// Deep immutable:
user.tags.push('admin');
// TypeError!

slides.code:
// Objects compare by reference
{ a: 1 } === { a: 1 }  // false

// Records compare by VALUE
#{ a: 1 } === #{ a: 1 }  // true!

// Works as Map keys
const cache = new Map();
cache.set(#{ x: 10, y: 20 }, 'hit');
cache.get(#{ x: 10, y: 20 }); // 'hit'!

// Works in Sets
const set = new Set();
set.add(#[1, 2, 3]);
set.has(#[1, 2, 3]); // true!
